function LxFormationCtrl:GetFormIntoColNameByRefId(refId,curSelIdx)
    local ref = GameTable.CombatTypeRef[refId]
    if not ref then return "" end
    local name = I18nText(ref.name)
    local isDefend = ref.troopTeams1 == 1
    ---@type LxFormationObj[]
    local battleList = ModuleCenter.Battle:GetFormationList(refId,isDefend)
    if #battleList > 0 then
        ---@type LxFormationObj
        local selFormation = battleList[curSelIdx]
        if selFormation and not string.isempty(selFormation.name) then
            name = selFormation.name
        end
    end
    return name
end

function LxFormationCtrl:GetRecordCombatTypeMap()
    if not self._recordCombatTypeMap then
        local recordCombatTypeMap = {}

        local disposeFunc = function(teamType,ref)
            local teamList = recordCombatTypeMap[teamType]
            if not teamList then
                teamList = {}
                recordCombatTypeMap[teamType] = teamList
            end
            table.insert(teamList,ref)
        end

        local recordTypeSelIdx = {}
        local type,troopTeams,troopTeams1
        for k,v in pairs(GameTable.CombatTypeRef) do
            recordTypeSelIdx[k] = 1
            type = v.type
            if type and type == 2 then
                --- 自定义编队
                disposeFunc(_CombatTeamType.DIY,v)
            else
                troopTeams = v.troopTeams
                if troopTeams and troopTeams == 1 then
                    disposeFunc(_CombatTeamType.ATTACK,v)
                end
                troopTeams1 = v.troopTeams1
                if troopTeams1 and troopTeams1 == 1 then
                    disposeFunc(_CombatTeamType.DEFEND,v)
                end
            end
        end
        for k,v in pairs(recordCombatTypeMap) do
            table.sort(v,function(a, b) return a.refId < b.refId end)
        end
        self._recordCombatTypeMap = recordCombatTypeMap
    end
    return self._recordCombatTypeMap
end

function LxFormationCtrl:GetRecordCombatTypeList()
    if not self._combatTypeList then
        local list = {}
        for k,v in pairs(GameTable.CombatTypeRef) do
            if v.troopTeams == 1 or v.troopTeams1 == 1 or v.type == 2 then
                table.insert(list,{
                    refId = k,
                    name = I18nText(v.name),
                    type = v.type,
                    troopTeams = v.troopTeams,
                    troopTeams1 = v.troopTeams1,
                    open = v.open,
                })
            end
        end
        table.sort(list,function(a, b) return a.refId < b.refId end)
        self._combatTypeList = list
    end
    return self._combatTypeList
end

function LxFormationCtrl:GetCombatTypeList(teamType)
    local recordCombatTypeMap = self:GetRecordCombatTypeMap()
    return recordCombatTypeMap[teamType]
end

function LxFormationCtrl:CheckIsDefend(teamType)
    return teamType == _CombatTeamType.DEFEND
end


function LxFormationCtrl:GetFormIntoColData(battleType,isDefend,index)
    local battleList = ModuleCenter.Battle:GetFormationList(battleType,isDefend)
    if not battleList or #battleList < 1 then return end

    ---@type LxFormationObj
    local formationObj = battleList[index]
    if not formationObj then return end

    local openHeroPositionMap = self:GetOpenHeroPositionMap()
    local unitIndex,positionInfo,name
    ---@type table<number, LxUnitPosObj>
    local positions = formationObj.positions or {}
    local hasHeroUp = false
    local heroMap = {}
    for key,val in pairs(positions) do
        if val:IsRole() then
        elseif val:IsHero() then
            unitIndex = val.index
            heroMap[unitIndex] = {
                index = unitIndex,
                isOpen = openHeroPositionMap[unitIndex],
                position = val,
            }
            if not hasHeroUp then
                hasHeroUp = true
            end
        end
    end
    local heroList = {}
    for idx = 1,BattleHeroPosCount do
        positionInfo = heroMap[idx]
        table.insert(heroList,{
            index = idx,
            position = positionInfo and positionInfo.position,
            isOpen = openHeroPositionMap[idx],
        })
    end
    table.sort(heroList,function(a, b) return a.index < b.index end)
    name = formationObj and formationObj.name
    if string.isempty(name) then
        name = CtrlCenter.Formation:GetFormIntoColNameByRefId(battleType,index)
    end
    return {
        heroList = heroList,
        power = formationObj and checknumber(formationObj.power) or 0,
        name = name,
        hasHeroUp = hasHeroUp,
    }
end

function LxFormationCtrl:GetOpenHeroPositionMap(roleLevel)
    roleLevel = roleLevel or ModuleCenter.Role:GetRoleLevel()
    local openHeroPositionMap = {}
    ---@param v V_CombatStationRef
    for k,v in pairs(GameTable.BattleStationRef) do
        if v.type == 1 and v.isOpen == 1 then
            local isOk = true
            for _i,conItem in ipairs(v.openCondition) do
                local conList = string.split(conItem, '=')
                if tonumber(conList[1]) == 151 then
                    isOk = tonumber(conList[2]) <= roleLevel
                end
                if not isOk then break end
            end
            openHeroPositionMap[v.refId] = isOk
        end
    end
    return openHeroPositionMap
end

function LxFormationCtrl:GetOpenCrestPositionMap(roleLevel)
    roleLevel = roleLevel or ModuleCenter.Role:GetRoleLevel()
    local openCrestPositionMap = {}
    ---@type V_CrestPositionRef
    local ref
    local type,openLevel,isOpen
    local tRef = GameTable.CrestPositionRef
    for i = 1,_CrestCount do
        ref = tRef[i]
        type = ref.type
        openLevel = ref.openLevel
        isOpen = roleLevel >= openLevel
        openCrestPositionMap[i] = {
            refId = ref.refId,
            type = type,
            name = I18nText(ref.name),
            isOpen = isOpen,
            openLevel = openLevel,
        }
    end
    return openCrestPositionMap
end

function LxFormationCtrl:GetFormIntoColDataByRefId(refId,isDefend)
    local ref = GameTable.CombatTypeRef[refId]
    if not ref then return end

    local openHeroPositionMap = self:GetOpenHeroPositionMap()
    local heroOrderMap = {}
    ---@type LxFormationObj[]
    local battleList = ModuleCenter.Battle:GetFormationList(refId,isDefend)
    ---@type LxFormationObj
    local formationObj
    ---@type table<number, LxUnitPosObj>
    local positions
    local unitIndex,positionInfo,name
    local fightType = ref.fightType
    local isAllEmpty = false
    for i = 1,fightType do
        formationObj = battleList[i] or {}
        positions = formationObj.positions or {}
        local hasHeroUp = false
        local heroMap = {}
        for key,val in pairs(positions) do
            if val:IsRole() then
            elseif val:IsHero() then
                unitIndex = val.index
                heroMap[unitIndex] = {
                    index = unitIndex,
                    isOpen = openHeroPositionMap[unitIndex],
                    position = val,
                }
                if not hasHeroUp then
                    hasHeroUp = true
                end
            end
        end
        local heroList = {}
        for idx = 1,BattleHeroPosCount do
            positionInfo = heroMap[idx]
            table.insert(heroList,{
                index = idx,
                position = positionInfo and positionInfo.position,
                isOpen = openHeroPositionMap[idx],
            })
        end
        table.sort(heroList,function(a, b) return a.index < b.index end)
        name = formationObj and formationObj.name
        if string.isempty(name) then
            name = CtrlCenter.Formation:GetFormIntoColNameByRefId(refId,i)
        end
        if not isAllEmpty and hasHeroUp then
            isAllEmpty = true
        end
        heroOrderMap[i] = {
            ---@type {index,position,isOpen}
            heroList = heroList,
            power = formationObj and checknumber(formationObj.power) or 0,
            name = name,
            hasHeroUp = hasHeroUp,
            order = formationObj.order
        }
    end
    return {
        ref = ref,
        heroOrderMap = heroOrderMap,
        isMoreFormation = fightType > 1,
        fightType = fightType,
        isAllEmpty = isAllEmpty,
        rank = ref.rank,
    }
end

