function LxFormationCtrl:CopyOrderFormation(data)
    ---@type V_CombatTypeRef
    local ref = data.ref
    local copyOrder,heroList,roleMap = data.copyOrder,data.heroList,data.roleMap
    ---@type LxFormationObj[]
    local battleList = ModuleCenter.Battle:GetFormationList(ref.refId,ref.troopTeams1 == 1)
    if not battleList or #battleList < 1 then return end
    local isDefend = ref.troopTeams1 == 1
    local formationGroup = {}
    local formationDefendGroup = {}
    local list
    if isDefend then
        list = formationDefendGroup
    else
        list = formationGroup
    end
    ---@type LxFormationObj
    local battle
    local fightType = ref.fightType
    for i = 1,fightType do
        battle = battleList[i]
        if battle and battle.order ~= copyOrder then
            table.insert(list,battleList[i] or {})
        end
    end
    local newFormation = ModuleCenter.Battle:NewFormation()
    newFormation.order = copyOrder
    local power = 0
    local openHeroPositionMap = self:GetOpenHeroPositionMap()
    local isHeroUp = false
    local isOpen
    local heroObjList
    ---@type LxHeroObj
    local heroObj
    for i,v in ipairs(heroList) do
        if not v.isEmpty then
            isOpen = openHeroPositionMap[i]
            if isOpen then
                local serverData = v.serverData
                if serverData then
                    heroObjList = ModuleCenter.Hero:GetRefHeroList(serverData.refId)
                    if heroObjList and #heroObjList > 0 then
                        heroObj = heroObjList[1]
                        power = power + checknumber(heroObj.power)
                        newFormation:AddHeroPos(i,heroObj)
                        if not isHeroUp then isHeroUp = true end
                    end
                end
            end
        end
    end
    newFormation.power = power
    if not isHeroUp then return end
    table.insert(list,newFormation)
    --- 暂无多队伍数据可测试，等数据到齐可测试
    if LOG_ERROR_ENABLED then
        printError("提示：",">>> 暂无多队伍数据可测试，等数据到齐可测试，暂时注释阵型设置代码")
    end
    if data.cb then data.cb() end
    HandlerCenter.Battle:SetFormationReq(ref.refId, formationGroup, formationDefendGroup)
end

---@return LxFormationObj
function LxFormationCtrl:GetFormation(itemData,newOrder)
    local positions = {}
    for i,v in ipairs(itemData.heroList) do
        if v.position then
            table.insert(positions,v.position)
        end
    end
    newOrder = newOrder or itemData.order
    ---@type LxFormationObj
    local formationObj = ModuleCenter.Battle:NewFormation({
        order = newOrder,
        power = itemData.power,
        positions = positions,
    })
    return formationObj
end



