function LxFormationCtrl:BattleVideo2FormationData(param)
    if not param.httpReportData then return end

    ---@type LxBattleReportData
    local reportData = require("LApp.gameplay.battle.data.LxBattleReportData"):new()
    reportData:InitData(param.httpReportData)
