    if battleType and battleType > 0 then
        ---@type V_CombatTypeRef
        local ref = GameTable.CombatTypeRef[battleType]

        local heroOrderMap = {}
        ---@type LxBattleFormationData
        local formationA = reportData.formationA

        local fightType = ref.fightType

        ------------------ 多阵容需要改下这里 start
        local recordRoleGridMap = {}
        local grids = formationA.grids
        local recordHeroGridMap = {}
        ---@param v LxBattleUnitGridData
        for k,v in pairs(grids) do
            if v:IsHero() then
                recordHeroGridMap[v.index] = v
            elseif v:IsRole() then
                recordRoleGridMap[v.index] = v
            end
        end
        ---@type table <number,LxBattleUnitGridData>
        local heroList = {}
        for i = 1,BattleHeroPosCount do
            local data = {}
            if recordHeroGridMap[i] then
                data.isEmpty = false
                data.serverData = recordHeroGridMap[i]
            else
                data.isEmpty = true
            end
            table.insert(heroList,data)
        end

        heroOrderMap[1] = {
            heroList = heroList,
            power = formationA.power,
            order = 1,
            recordRoleGridMap = recordRoleGridMap
        }
        ------------------ 多阵容需要改下这里 end

        ShowPanel(UiNames.ReportFormationCopy,{
            formationData = {
                ref = ref,
                heroOrderMap = heroOrderMap,
                fightType = fightType,
                isMoreFormation = fightType > 1,
            },
            name = param.name or ""
        })
    end
end


function LxFormationCtrl:GetCopyCrestList(crestTypeMap)
    crestTypeMap = crestTypeMap or {}

    local CrestMap = {}
    local roleLevel =  ModuleCenter.Role:GetRoleLevel()
    ---@type V_CrestPositionRef
    local ref
    local type,openLevel,refId
    local tRef = GameTable.CrestPositionRef
    for i = 1,_CrestCount do
        ref = tRef[i]
        refId = ref.refId
        type = ref.type
        openLevel = ref.openLevel
        local CrestList = CrestMap[type]
        if not CrestList then
            CrestList = {}
            CrestMap[type] = CrestList
        end
        table.insert(CrestList,{
            refId = refId,
            type = ref.type,
            openLevel = openLevel,
            isOpen = roleLevel >= openLevel,
            name = I18nText(ref.name),
            crestObj = crestTypeMap[refId],
        })
    end
    return CrestMap[1],CrestMap[2]
end


function LxFormationCtrl:GetInitCombatStationEffRefData()
    if not self._initCombatStationEffRefData then
        local datas = {}

        ---@type number 阵营类型
        local campType
        ---@type number 阵营数量
        local campNum
        local attrName,attrValueStr
        local attrRefId
        local data
        local specialStation = GameTable.BattleConfigRef["specialStation"]
        for k,v in pairs(GameTable.CombatStationEffRef) do
            local conditions = {}
            local normalRaces = {}
            local specialRaces = {}
            for idx,val in ipairs(v.condition) do
                val = string.split(val,"=")
                campType = checknumber(val[1])
                campNum = checknumber(val[2])
                data = {
                    campType = campType,
                    campNum = campNum,
                }
                table.insert(conditions,data)

                if campType == specialStation then
                    table.insert(specialRaces,data)
                else
                    table.insert(normalRaces,data)
                end
            end

            ---@type V_Attr[]
            local value = LxDataHelper.ParseAttrList(v.value)
            local valueStrs = {}
            for idx,attr in ipairs(value) do
                attrRefId = attr.refId
                attrName = LxDataHelper.GetCombatAttributeFullName(attrRefId, attr.tar)
                attrValueStr = LxDataHelper.ConvertAttrValue(attrRefId, attr.value)
                table.insert(valueStrs,string.replace(I18nText(2241),attrName,attrValueStr))
            end

            table.insert(datas,{
                refId = k,
                num = v.num,

                --- condition start
                condition = v.condition,
                conditions = conditions,
                normalRaces = normalRaces,
                specialRaces = specialRaces,
                --- condition end

                icon = v.icon,
                effect = v.effect,

                --- value start
                value = value,
                valueStr = table.concat(valueStrs,I18nText(2242)),
                --- value end

                name = I18nText(v.name),
                conDec = I18nText(v.conDec),
            })
        end
        table.sort(datas,function (a,b) return a.refId < b.refId end)
        self._initCombatStationEffRefData = datas
    end
    return self._initCombatStationEffRefData
end

---@param formationObj LxFormationObj
function LxFormationCtrl:CalcCombatStationEff(formationObj)
    --- 存在的阵容数量
    local calcRaceNum = 0
    local calcRaceMap = {}
    local onlyRaceType,onlyRaceNum
    local heroRace
    local specialStation = GameTable.BattleConfigRef["specialStation"]
    for k,v in pairs(formationObj.positions) do
        if not v:IsRole() then
            heroRace = LxDataHelper.GetHeroRaceType(v.heroRefId)
            if not calcRaceMap[heroRace] then
                calcRaceNum = calcRaceNum + 1
            end
            local calcNum = calcRaceMap[heroRace] or 0
            calcRaceMap[heroRace] = calcNum + 1

            if heroRace ~= specialStation then
                if not onlyRaceType then
                    onlyRaceType = heroRace
                    onlyRaceNum = 1
                elseif onlyRaceType == heroRace then
                    onlyRaceNum = onlyRaceNum + 1
                end
            end
        end
    end

    if calcRaceNum < 1 then return end

    local specialNum = calcRaceMap[specialStation]
    local hasSpecial = specialNum and specialNum > 0
    if hasSpecial then
        --- 特殊阵营上阵后自动转为上阵数量最多的普通阵营，进行激活判断
        if calcRaceNum == 1 then
            --- 单纯 特殊阵容
            return self:CalcSpecialCombatStationEff(calcRaceMap,1)
        else
            local isSameNum = false
            if calcRaceNum > 2 then
                --- 除 特殊阵营外，其他阵营数量大于等于2时，进行激活判断
                isSameNum = true
                local maxRaceNum,maxRaceType
                local recordNum
                for k,v in pairs(calcRaceMap) do
                    if not calcRaceMap[specialStation] then
                        if isSameNum then
                            if not recordNum then
                                recordNum = v
                            elseif recordNum ~= v then
                                isSameNum = false
                            end
                        end
                        if not maxRaceNum then
                            maxRaceType = k
                            maxRaceNum = v
                        elseif maxRaceNum < v then
                            maxRaceType = k
                            maxRaceNum = v
                        end
                    end
                end
                if isSameNum then
                    --- 若数量相同，则根据上阵先后进行激活判断，优先转为后上阵的普通阵营
                else
                    local newCalcRaceNum = 0
                    local newCalcRaceMap = {}
                    for k,v in pairs(calcRaceMap) do
                        if k ~= specialStation then
                            newCalcRaceMap[k] = v
                            newCalcRaceNum = newCalcRaceNum + 1
                        end
                    end
                    if maxRaceType and maxRaceNum and newCalcRaceMap[maxRaceType] then
                        local curNum = newCalcRaceMap[maxRaceType]
                        newCalcRaceMap[maxRaceType] = curNum + maxRaceNum
                    end
                    return self:CalcNormalCombatStationEff(newCalcRaceMap,newCalcRaceNum)
                end
            else
                --- 只有特殊 + 一个阵营，直接列为该阵营的数量
                local newCalcRaceMap = {}
                newCalcRaceMap[onlyRaceType] = onlyRaceNum + specialNum
                return self:CalcNormalCombatStationEff(newCalcRaceMap,1)
            end
        end
    else
        return self:CalcNormalCombatStationEff(calcRaceMap,calcRaceNum)
    end
end

---@param raceMap table<number, number> 种族类型，数量
---@param raceNum number 阵容数量
function LxFormationCtrl:CalcNormalCombatStationEff(raceMap,raceNum)
    local datas = self:GetInitCombatStationEffRefData()
    local num
    local campType,campNum
    local stationEffData
    for i,data in ipairs(datas) do
        num = data.num
        if raceNum == num then
            local enoughNum = 0
            for idx,val in ipairs(data.normalRaces) do
                campType = val.campType
                campNum = val.campNum
                if raceMap[campType] and raceMap[campType] == campNum then
                    enoughNum = enoughNum + 1
                end
            end
            if enoughNum >= num then
                stationEffData = data
            end
        end
    end
    return stationEffData
end


--- 特殊的阵营计算，仅全部特殊阵营的使用
---@param raceMap table<number, number> 种族类型，数量
---@param raceNum number 阵容数量
function LxFormationCtrl:CalcSpecialCombatStationEff(raceMap,raceNum)
    local datas = self._initSpecialCSEffData
    if not datas then
        datas = {}
        local initDatas = self:GetInitCombatStationEffRefData()
        local specialRaces
        for i,v in ipairs(initDatas) do
            specialRaces = v.specialRaces
            if specialRaces and #specialRaces > 0 then
                table.insert(datas,v)
            end
        end
        self._initSpecialCSEffData = datas
    end
    local num
    local campType,campNum
    local stationEffData
    for i,data in ipairs(datas) do
        num = data.num
        if raceNum >= num then
            local enoughNum = 0
            for idx,val in ipairs(data.specialRaces) do
                campType = val.campType
                campNum = val.campNum
                if raceMap[campType] and raceMap[campType] >= campNum then
                    enoughNum = enoughNum + 1
                end
            end
            if enoughNum >= num then
                stationEffData = data
            end
        end
    end
    return stationEffData
end

---@param formation LxFormationObj
function LxFormationCtrl:OpenCombatStationEffUIByFormationObj(formation)
    local data = self:GetRaceAddRefByBattleType(formation)
    local actRefId = data and data.refId or 0
    ShowPanel(UiNames.CombatStationEff,{
        actRefId = actRefId,
    })
end


--- 获取种族光环配置
function LxFormationCtrl:GetRaceAddRefByBattleType(formationData, isMonster)
    if not formationData then
        return
    end
    local curActRef
    local raceMap = {}  --- key 种族refId v 数量
    local heroRaceAddRefList = GameTable.HeroRaceAddRef
    local monsterList = GameTable.MonsterAttrRef
    local heroRefList = GameTable.CharacterRef
    --- 同一个种族的最大数量
    local maxRaceNum = 0
    if not table.isempty(formationData) then
        for _, v in pairs(formationData.positions) do
            local raceType
            local heroRef = heroRefList[v.refId or v.heroRefId]
            if heroRef then
                raceType = heroRef.raceType
            else
                local ref = monsterList[v.heroRefId]
                raceType = ref.raceType
            end
            if not raceMap[raceType] then
                raceMap[raceType] = 0
            end
            raceMap[raceType] = raceMap[raceType] + 1
            if maxRaceNum < raceMap[raceType] then
                maxRaceNum = raceMap[raceType]
            end
        end
    end
    for _, v in ipairs(heroRaceAddRefList) do
        for _, v2 in ipairs(v.condition) do
            local cond = string.split(v2, "=")
            local raceType = checknumber(cond[1])
            local needNum = checknumber(cond[2])
            if maxRaceNum < needNum then
                return curActRef
            end
            if raceMap[raceType] and raceMap[raceType] >= needNum then
                curActRef = v
            end
        end
    end
    return curActRef
end
--- 判断英雄是否在主线阵容里面
function LxFormationCtrl:CheckHeroIsInnerIns(heroObj)
    local formationData = ModuleCenter.Battle:GetFormation(BattleType.Adventure)    -- 阵容信息
    if not table.isempty(formationData) then
        for _, v in pairs(formationData.positions) do
            if v.id == heroObj.id then
                return true
            end
        end
    end
    return false
end

return LxFormationCtrl